const items = $input.all();

// Agrupar correctamente evitando duplicados del combineAll
const billeterasMap = new Map();
const compromisosMap = new Map();
const gastosMesMap = new Map();
let presupuesto = null;
let patrimonio = null;

for (const item of items) {
  const d = item.json;

  // Billetera: tiene campo "billetera"
  if (d.billetera && !billeterasMap.has(d.billetera)) {
    billeterasMap.set(d.billetera, d);
  }

  // Presupuesto: tiene campo "presupuesto_deseos"
  if (d.presupuesto_deseos !== undefined && presupuesto === null) {
    presupuesto = d;
  }

  // Compromisos: tiene campo "monto_cuota"
  if (d.monto_cuota !== undefined && d.descripcion) {
    const key = `${d.descripcion}_${d.cuota_actual}_${d.total_cuotas}`;
    if (!compromisosMap.has(key)) compromisosMap.set(key, d);
  }

  // Patrimonio: tiene campo "patrimonio_actual"
  if (d.patrimonio_actual !== undefined && patrimonio === null) {
    patrimonio = d;
  }

  // Gastos mes: tiene campo "categoria" y "total" pero NO "monto_cuota"
  if (d.categoria && d.total !== undefined && d.monto_cuota === undefined) {
    if (!gastosMesMap.has(d.categoria)) gastosMesMap.set(d.categoria, d);
  }
}

const billeteras = [...billeterasMap.values()];
const compromisosList = [...compromisosMap.values()];
const gastosMes = [...gastosMesMap.values()];

const fmt = n => Number(n || 0).toLocaleString('es-AR', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
const totalBilleteras = billeteras.reduce((sum, b) => sum + Number(b.saldo || 0), 0);
const totalCuotas = compromisosList.reduce((sum, c) => sum + Number(c.monto_cuota || 0), 0);

const fecha = new Date().toLocaleDateString('es-AR', { weekday: 'long', day: 'numeric', month: 'long' });
const fechaCap = fecha.charAt(0).toUpperCase() + fecha.slice(1);

// Tendencia patrimonio
let tendenciaTexto = '';
if (patrimonio && patrimonio.cambio !== null) {
  const cambio = Number(patrimonio.cambio);
  const signo = cambio >= 0 ? '📈 +' : '📉 ';
  tendenciaTexto = `${signo}$${fmt(Math.abs(cambio))} vs semana anterior`;
} else {
  tendenciaTexto = 'Primera semana registrada';
}

// Salud presupuesto
let saludMes = '';
if (presupuesto) {
  const gastadoPct = presupuesto.presupuesto_deseos > 0
    ? Math.round((Number(presupuesto.gastado_deseos) / Number(presupuesto.presupuesto_deseos)) * 100)
    : 0;
  const diasMes = new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0).getDate();
  const diaActual = new Date().getDate();
  const tiempoPct = Math.round((diaActual / diasMes) * 100);
  const diff = gastadoPct - tiempoPct;
  if (diff > 15) saludMes = '🔴 Gastos acelerados';
  else if (diff > 0) saludMes = '🟡 Ritmo normal';
  else saludMes = '🟢 Buen ritmo';
}

// Construir mensaje
let msg = '';
msg += `📊 *RESUMEN SEMANAL*\n`;
msg += `📅 ${fechaCap}\n`;
msg += `━━━━━━━━━━━━━━━━\n\n`;

// BILLETERAS
msg += `💰 *BILLETERAS*\n`;
for (const b of billeteras) {
  const icono = b.codigo === 'FONDO_JUAN' ? '🏦' : b.codigo === 'FONDO_AUTO' ? '🚗' : '💵';
  let linea = `${icono} ${b.billetera}: *$${fmt(b.saldo)}*`;
  if (b.meta && b.progreso_pct) {
    const barras = Math.floor(b.progreso_pct / 10);
    const barra = '█'.repeat(barras) + '░'.repeat(10 - barras);
    linea += `\n   ${barra} ${b.progreso_pct}%`;
  }
  msg += linea + '\n';
}
msg += `💼 *Total: $${fmt(totalBilleteras)}*\n`;
msg += `${tendenciaTexto}\n\n`;

// PRESUPUESTO MES
if (presupuesto) {
  const disponible = Number(presupuesto.disponible);
  const gastadoDeseos = Number(presupuesto.gastado_deseos || 0);
  const presDeseos = Number(presupuesto.presupuesto_deseos);
  const gastadoPct = presDeseos > 0 ? Math.round((gastadoDeseos / presDeseos) * 100) : 0;
  const mesNombre = new Date().toLocaleDateString('es-AR', { month: 'long' }).toUpperCase();

  msg += `📋 *PRESUPUESTO ${mesNombre}*\n`;
  msg += `💵 Ingreso: $${fmt(presupuesto.ingreso)} (TC $${fmt(presupuesto.tipo_cambio)})\n`;
  msg += `🏠 Necesidades: $${fmt(presupuesto.presupuesto_necesidades)}\n`;
  msg += `🎯 Deseos: $${fmt(presupuesto.presupuesto_deseos)}\n`;
  msg += `   Gastado: $${fmt(gastadoDeseos)} (${gastadoPct}%) ${saludMes}\n`;
  msg += `💎 Ahorro objetivo: $${fmt(presupuesto.presupuesto_ahorro)}\n`;
  msg += `💳 Cuotas TC: $${fmt(presupuesto.compromisos_tc)}\n`;
  const iconDisp = disponible >= 0 ? '✅' : '⚠️';
  msg += `${iconDisp} *Libre para gastar: $${fmt(disponible)}*\n\n`;
}

// CUOTAS ACTIVAS
if (compromisosList.length > 0) {
  msg += `💳 *CUOTAS ACTIVAS (${compromisosList.length})*\n`;
  for (const c of compromisosList) {
    msg += `• ${c.descripcion}: $${fmt(c.monto_cuota)}/mes (${c.cuota_actual}/${c.total_cuotas})\n`;
  }
  msg += `Total: *$${fmt(totalCuotas)}/mes*\n\n`;
}

// GASTOS DEL MES POR CATEGORÍA
if (gastosMes.length > 0) {
  const totalGastado = gastosMes.reduce((sum, g) => sum + Number(g.total), 0);
  msg += `🧾 *TOP GASTOS DEL MES*\n`;
  for (const g of gastosMes) {
    const pct = Math.round((Number(g.total) / totalGastado) * 100);
    msg += `• ${g.categoria}: $${fmt(g.total)} (${pct}%)\n`;
  }
  msg += `\n`;
}

msg += `━━━━━━━━━━━━━━━━\n`;
msg += `💡 _Consultame antes de gastar._`;

return { mensaje: msg };
